  ('customs-7fec267e-moex-00078', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設有兩個寡占廠商生產同質的商品，並進行古爾諾（Cournot）模式的競爭。相較於完全競爭市場，下 列敘述何者錯誤？', '["寡占會造成社會福利損失", "寡占市場的總產量較高", "寡占廠商獲得的利潤較高", "寡占廠商有決定價格的能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00079', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列何者不屬於生產要素？', '["土地", "資本", "企業能力", "政府"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00080', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '有關補償性工資差異（compensatingwagedifferentials），下列敘述何者正確？', '["雇主給付工資的主要原因，為補償勞工花在工作的時間", "如果發生工安意外時，雇主應該負擔補償的責任", "雇主發放的年終獎金或是生日禮券，都算是補償性工資", "為補償勞工面對較高的危險或不舒服的工作環境，勞工所領取的較高工資"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00081', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '社會僅有a與b兩人。當公共財提供數量為1、2、3、4 單位時，a得到的邊際利益分別為4元、3元、2 元、1元，而b得到的邊際利益分別為6元、5元、4元、3元。當政府提供每單位公共財之成本為5元， 則政府應提供幾單位的公共財，可使社會淨利益（等於公共財之總利益與提供成本之差距）最大？', '["1", "2", "3", "4"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00082', 'customs-7fec267e', 'customs-7fec267e-moex-113-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '小李的效用函數為U(C,L)，C為消費，L為休閒時間。假設工時（H）等於時間總數（T）減去休閒時間（L）， 小李的預算限制式為C=w·H+V，w為工資，V為非勞動所得。工資變動對於休閒時間的需求會產生替代效果 與所得效果。下圖為小李的勞動供給曲線，對其而言下列敘述何者正確？ 工資 （w） 工時（H）', '["工資上升帶來的替代效果總是大於所得效果", "工資上升帶來的所得效果總是大於替代效果", "只有在工資夠高時，工資上升帶來的替代效果才大於所得效果", "只有在工資夠高時，工資上升帶來的所得效果才大於替代效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "3fac22dc26b5", "answer_pdf_sha1": "8e5c03118776", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "142", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
